/**
 * Registry of every Kumiki package available in the Playground.
 *
 * Generated by hand for now; future tooling can derive this from
 * `pnpm-workspace.yaml`. Each entry has:
 *   - `slug`: URL slug for `/play/<slug>`
 *   - `name`: full npm package name
 *   - `layer`: 0–5 (matches docs/design/02-architecture.md)
 *   - `summary`: one-line description
 *   - `live`: whether the package has a live, interactive demo (Layer 4/5 only)
 *   - `apgUrl`: matching APG pattern URL, if any
 *
 * The slug omits the `@kumiki/` prefix — `@kumiki/component-toggle` → `component-toggle`.
 */

import type { Component } from 'svelte';

export interface PlaygroundEntry {
  slug: string;
  name: string;
  layer: 0 | 1 | 2 | 3 | 4 | 5;
  summary: string;
  /** True when an interactive demo Svelte component is provided. */
  live: boolean;
  apgUrl?: string;
  /** Status hint for the UI badge. */
  status: 'unreleased' | 'preview' | 'stable';
}

